// Phase A Optimization: Cached text transform builder
const buildTextTransform = ({ x, y, rotate, skewX, skewY, scaleX, scaleY }, cache = null) => {
  // Create cache key
  const cacheKey = `${x}-${y}-${rotate}-${skewX}-${skewY}-${scaleX}-${scaleY}`;
  
  // Check cache if provided
  if (cache && cache.has(cacheKey)) {
    return cache.get(cacheKey);
  }
  
  // Calculate transform
  const sx = scaleX != null && scaleX !== 0 ? scaleX : 1;
  const sy = scaleY != null && scaleY !== 0 ? scaleY : 1;
  const scale = (sx !== 1 || sy !== 1) ? ` scale(${sx}, ${sy})` : '';
  const xN = Number(x);
  const yN = Number(y);
  const transform = `translate(${xN}, ${yN}) rotate(${rotate})${scale} skewX(${skewX}) skewY(${skewY}) translate(${-xN}, ${-yN})`;
  
  // Cache if provided
  if (cache) {
    try {
      cache.set(cacheKey, transform);
      const cap = 256;
      if (typeof cache.size === 'number' && cache.size > cap && typeof cache.keys === 'function' && typeof cache.delete === 'function') {
        while (cache.size > cap) {
          const it = cache.keys();
          const k = it && typeof it.next === 'function' ? it.next().value : undefined;
          cache.delete(k);
        }
      }
    } catch (e) {
      // ignore
    }
  }
  
  return transform;
};

// Transform builder for <g> groups (do NOT include translate(-x,-y)).
// buildTextTransform is designed for elements that also set x/y attributes.
const buildGroupTransform = ({ x, y, rotate, skewX, skewY, scaleX, scaleY }, cache = null) => {
  const cacheKey = `g:${x}-${y}-${rotate}-${skewX}-${skewY}-${scaleX}-${scaleY}`;
  if (cache && cache.has(cacheKey)) {
    return cache.get(cacheKey);
  }
  const sx = scaleX != null && scaleX !== 0 ? scaleX : 1;
  const sy = scaleY != null && scaleY !== 0 ? scaleY : 1;
  const scale = (sx !== 1 || sy !== 1) ? ` scale(${sx}, ${sy})` : '';
  const xN = Number(x);
  const yN = Number(y);
  const transform = `translate(${xN}, ${yN}) rotate(${rotate})${scale} skewX(${skewX}) skewY(${skewY})`;
  if (cache) {
    try {
      cache.set(cacheKey, transform);
      const cap = 256;
      if (typeof cache.size === 'number' && cache.size > cap && typeof cache.keys === 'function' && typeof cache.delete === 'function') {
        while (cache.size > cap) {
          const it = cache.keys();
          const k = it && typeof it.next === 'function' ? it.next().value : undefined;
          cache.delete(k);
        }
      }
    } catch (e) {
      // ignore
    }
  }
  return transform;
};

const buildHouseTemperatureGroupTransform = (config, textPositions) => {
  const htPos = (textPositions && textPositions.home_temperature) ? textPositions.home_temperature : DEFAULT_TEXT_POSITIONS.home_temperature;
  const htDef = DEFAULT_TEXT_POSITIONS.home_temperature;
  const ax = 400 + (Number(config.house_temperature_offset_x) || 0);
  const ay = 137 + (Number(config.house_temperature_offset_y) || 0);
  const x = ax + (htPos.x - htDef.x);
  const y = ay + (htPos.y - htDef.y);
  const rotate = (Number(config.house_temperature_rotation) || 0) + (htPos.rotate - htDef.rotate);
  return buildGroupTransform({
    x,
    y,
    rotate,
    skewX: htPos.skewX,
    skewY: htPos.skewY,
    scaleX: htPos.scaleX,
    scaleY: htPos.scaleY
  });
};

