      miniCamMotionLiveOverlays: Array.from({ length: LUMINA_MINI_CAM_SLOTS }, (_, i) => root.querySelector(`[data-role="mini-cam-motion-live-overlay-${i + 1}"]`)),
      miniCamMotionLiveOverlayBodies: Array.from({ length: LUMINA_MINI_CAM_SLOTS }, (_, i) => root.querySelector(`[data-role="mini-cam-motion-live-overlay-body-${i + 1}"]`)),
      batteryOverlayImage: root.querySelector('[data-role="battery-overlay-image"]'),
      debugGrid: root.querySelector('[data-role="debug-grid"]'),
      debugCoords: root.querySelector('[data-role="debug-coordinates"]'),
      debugAnimationOverlay: root.querySelector('[data-role="debug-animation-overlay"]'),
      title: root.querySelector('[data-role="title-text"]'),
      gridBoxGroup: root.querySelector('[data-role="grid-box"]'),
      // Optimized: use for loop instead of map for better performance
      gridBoxLines: (() => {
        const lines = [];
        for (let i = 0; i < 4; i++) {
          lines[i] = root.querySelector(`[data-role="grid-box-line-${i}"]`);
        }
        return lines;
      })(),
      pvBoxGroup: root.querySelector('[data-role="pv-box"]'),
      pvBoxLines: (() => {
        const lines = [];
        for (let i = 0; i < 2; i++) {
          lines[i] = root.querySelector(`[data-role="pv-box-line-${i}"]`);
        }
        return lines;
      })(),
      socBarGroup: root.querySelector('[data-role="soc-bar-1"]'),
