    const locL1 = document.createElementNS(NS, 'text');
    locL1.setAttribute('x', String(rightColX + rightColW - 8));
    locL1.setAttribute('y', String(locY + 18));
    locL1.setAttribute('text-anchor', 'end');
    locL1.setAttribute('fill', '#9ee8ff');
    locL1.setAttribute('font-size', '7');
    locL1.setAttribute('font-family', 'ui-monospace,monospace');
    locL1.textContent = (ui.locLbl + ': ' + stLine).slice(0, 28).toUpperCase();
    gRoot.appendChild(locL1);

    const locL2 = document.createElementNS(NS, 'text');
    locL2.setAttribute('x', String(rightColX + rightColW - 8));
    locL2.setAttribute('y', String(locY + 32));
    locL2.setAttribute('text-anchor', 'end');
    locL2.setAttribute('fill', 'rgba(0,255,255,0.55)');
    locL2.setAttribute('font-size', '6');
    locL2.setAttribute('font-family', 'ui-monospace,monospace');
