      r.setAttribute('rx', '6');
      r.setAttribute('ry', '6');
      r.setAttribute('fill', 'rgba(22,28,38,0.8)');
      r.setAttribute('stroke', 'rgba(0,255,255,0.55)');
      const t = document.createElementNS(NS, 'text');
      t.setAttribute('x', String(bw / 2));
      t.setAttribute('y', '16');
      t.setAttribute('text-anchor', 'middle');
      t.setAttribute('fill', '#00f9f9');
