      miniCamItems.push({ value: `mini_cam_${i}_bar`, label: `Mini Cam ${i} bar`, x: `mini_cam_${i}_bar_x`, y: `mini_cam_${i}_bar_y`, w: `mini_cam_${i}_bar_width`, h: `mini_cam_${i}_bar_height`, minW: 1, maxW: 200, minH: 1, maxH: 20 });
      miniCamItems.push({ value: `mini_cam_${i}_motion_popup`, label: `Mini Cam ${i} motion popup`, x: `mini_cam_${i}_motion_popup_x`, y: `mini_cam_${i}_motion_popup_y`, w: `mini_cam_${i}_motion_popup_width`, h: `mini_cam_${i}_motion_popup_height`, minW: 1, maxW: 800, minH: 1, maxH: 450 });
