    miniCamGeomRow.appendChild(miniCamGeomTitle);
    const miniCamX = mkPopupNum((localeStrings && localeStrings.fields && localeStrings.fields.editor_popup_x) || 'X (pos.)', 'X position (0-800)');
    const miniCamY = mkPopupNum((localeStrings && localeStrings.fields && localeStrings.fields.editor_popup_y) || 'Y (pos.)', 'Y position (0-450)');
    const miniCamW = mkPopupNum((localeStrings && localeStrings.fields && localeStrings.fields.editor_popup_w) || 'W (width)', 'Width (1-260)');
    const miniCamH = mkPopupNum((localeStrings && localeStrings.fields && localeStrings.fields.editor_popup_h) || 'H (height)', 'Height (1-120)');
    miniCamGeomRow.appendChild(miniCamX.wrap);
