          pv_string_5_label: { label: 'Etiqueta cadena 5', helper: 'Etiqueta de la quinta cadena (p. ej. S5).' },
          pv_string_6_label: { label: 'Etiqueta cadena 6', helper: 'Etiqueta de la sexta cadena (p. ej. S6).' },
