          overlay_image_3_enabled: { label: 'Habilitar imagen superpuesta 3', helper: 'Habilite o deshabilite la tercera imagen superpuesta. Agregue más elementos visuales a su panel de energía.' },
          overlay_image_3: { label: 'Imagen superpuesta 3 ruta', helper: 'Ruta a la tercera imagen PNG. Ejemplo predeterminado: /local/community/lumina-energy-card/Pool.png. Perfecto para mostrar piscinas, calentadores de agua u otros consumidores de energía.' },
