  _loadVideoGuidePreviewMeta_(url) {
    try {
      this._videoGuideMetaCache = this._videoGuideMetaCache || {};
      this._videoGuideMetaPending = this._videoGuideMetaPending || {};
      if (this._videoGuideMetaCache[url]) return Promise.resolve(this._videoGuideMetaCache[url]);
      if (this._videoGuideMetaPending[url]) return this._videoGuideMetaPending[url];
      const endpoint = 'https://www.tiktok.com/oembed?url=' + encodeURIComponent(String(url || ''));
      const p = fetch(endpoint)
        .then((res) => (res && res.ok ? res.json() : null))
        .then((data) => {
          const meta = {
            title: data && typeof data.title === 'string' ? data.title.trim() : '',
            thumbnailUrl: data && typeof data.thumbnail_url === 'string' ? data.thumbnail_url.trim() : ''
          };
          this._videoGuideMetaCache[url] = meta;
          delete this._videoGuideMetaPending[url];
          return meta;
        })
        .catch(() => {
          delete this._videoGuideMetaPending[url];
          return { title: '', thumbnailUrl: '' };
        });
      this._videoGuideMetaPending[url] = p;
      return p;
    } catch (e) {
      return Promise.resolve({ title: '', thumbnailUrl: '' });
    }
  }

